#include <iostream>
#include <unordered_map>
#include <string>

// Define the User structure
struct User {
    std::string username;
    int age;
    std::string email;
};

// Function to search for a user in the hash table and return their profile data
User* findUserProfile(std::unordered_map<std::string, User>& users, const std::string& username) {
    auto it = users.find(username);
    if (it != users.end()) {
        return &it->second;
    }
    return nullptr;
}

int main() {
    // Example usage
    std::unordered_map<std::string, User> userDatabase;
    userDatabase["john_doe"] = {"John Doe", 30, "john.doe@example.com"};
    userDatabase["jane_smith"] = {"Jane Smith", 25, "jane.smith@example.com"};

    const std::string searchUsername = "john_doe";
    User* userProfile = findUserProfile(userDatabase, searchUsername);

    if (userProfile) {
        std::cout << "User found: " << userProfile->username
                  << ", Age: " << userProfile->age
                  << ", Email: " << userProfile->email << std::endl;
    } else {
        std::cout << "User not found." << std::endl;
    }

    return 0;
}